mapper.update:
UPDATE STOCUSER SET
     MOD_DATE = SYSDATE
    ,MOD_USER_ID = #{ses.userId}
    ,USER_NM = #{USER_NM}
    ,USER_NM_ENG = #{USER_NM_ENG}

    ,PASSWORD = #{PASSWORD}
    ,PW_RESET_FLAG = '1'
    ,PW_RESET_DATE = SYSDATE
    ,PW_WRONG_CNT = 0
    ,COMPULSION_PW_RESET_FLAG = '0'

    ,TEL_NUM =  #{TEL_NUM} 
    ,CELL_NUM =  #{CELL_NUM} 
    ,FAX_NUM =  #{FAX_NUM} 
    ,EMAIL =  #{EMAIL} 
    ,POSITION_NM = #{POSITION_NM}
    ,DUTY_NM = #{DUTY_NM}
 WHERE USER_ID = #{USER_ID}
   AND DEL_FLAG = '0'
   AND GATE_CD = #{ses.gateCd}

UPDATE STOCCVUR SET
     MOD_DATE = SYSDATE
    ,MOD_USER_ID = #{ses.userId}
    ,USER_NM = #{USER_NM}

    ,PASSWORD = #{PASSWORD}
    ,PW_RESET_FLAG = '1'
    ,PW_RESET_DATE = SYSDATE
    ,PW_WRONG_CNT = 0

    ,POSITION_NM = #{POSITION_NM}
    ,DUTY_NM = #{DUTY_NM}
    ,TEL_NUM =  #{TEL_NUM} 
    ,FAX_NUM = #{FAX_NUM} 
    ,CELL_NUM =  #{CELL_NUM} 
    ,EMAIL =  #{EMAIL} 
 WHERE GATE_CD = #{ses.gateCd}
   AND USER_ID = #{USER_ID}
   AND DEL_FLAG = '0'

mapper.select:
SELECT
    GETCOMCODE(#{ses.gateCd}, 'M054', #{USER_DATE_FORMAT_CD}, '0', #{ses.langCd}) AS USER_DATE_FORMAT_VALUE
  FROM STOCUSER
 WHERE USER_ID = #{ses.userId}
   AND DEL_FLAG = '0'
   AND GATE_CD = #{ses.gateCd}
